"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[2848],{6251(t,e,a){a.r(e),a.d(e,{comp:()=>n,data:()=>o});var r=a(641);const d={},n=(0,a(6262).A)(d,[["render",function(t,e){return(0,r.uX)(),(0,r.CE)("div",null,[...e[0]||(e[0]=[(0,r.Fv)('<h1 id="my-wallet" tabindex="-1"><a class="header-anchor" href="#my-wallet"><span>My Wallet</span></a></h1><p><strong><code>/my-account/my_wallet/</code></strong> — customer-facing wallet endpoint. Top up, transfer, view ledger, partial-pay at checkout.</p><p><img src="/auctions-for-woocommerce/images/screenshots/front-wallet-balance.png" alt="Customer Wallet panel — current balance, Add to Wallet form, transactions ledger and (when enabled) Wallet Transfer"></p><h2 id="what-the-page-shows" tabindex="-1"><a class="header-anchor" href="#what-the-page-shows"><span>What the page shows</span></a></h2><table><thead><tr><th>Section</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Balance card</strong></td><td>Current available balance, big and prominent</td></tr><tr><td><strong>Add to Wallet</strong></td><td>Top-up form — enter amount, click Add to Cart</td></tr><tr><td><strong>Transactions</strong></td><td>Filterable ledger of all wallet movements</td></tr><tr><td><strong>Wallet Transfer</strong> (if enabled)</td><td>Send to another customer by email</td></tr></tbody></table><p>The page is wrapped in the auction plugin&#39;s <code>.wkafw-wallet-skin</code> styling so it matches the rest of your auction UI.</p><h2 id="adding-funds-top-up" tabindex="-1"><a class="header-anchor" href="#adding-funds-top-up"><span>Adding funds (top-up)</span></a></h2><ol><li>Enter amount in the <strong>Add to Wallet</strong> input</li><li>Click <strong>Add to Cart</strong> — adds a special wallet-top-up product to cart</li><li>Proceed to <strong>Checkout</strong> — pay via any WooCommerce gateway</li><li>After successful payment, your wallet balance updates automatically</li></ol><table><thead><tr><th>Constraint</th><th>Default</th><th>Setting</th></tr></thead><tbody><tr><td>Min top-up</td><td>1</td><td>submodule setting</td></tr><tr><td>Max top-up</td><td>10,000</td><td>submodule setting</td></tr><tr><td>Top-up product</td><td>auto-created hidden product</td><td><code>wkafw_wallet_topup_product_id</code></td></tr></tbody></table><div class="hint-container tip"><p class="hint-container-title">Multiple currencies</p><p>Wallets are single-currency per customer (matches your WooCommerce store currency). If you need multi-currency, run separate stores or use a multi-currency plugin.</p></div><h2 id="transactions-ledger" tabindex="-1"><a class="header-anchor" href="#transactions-ledger"><span>Transactions ledger</span></a></h2><p>Filterable list, latest first.</p><table><thead><tr><th>Column</th><th>Source</th></tr></thead><tbody><tr><td>Date</td><td><code>transaction_date</code></td></tr><tr><td>Reference</td><td>top-up order ID, transfer ID, withdrawal ID, or system note</td></tr><tr><td>Amount</td><td>currency-formatted</td></tr><tr><td>Type</td><td><code>cr</code> (credit) / <code>dr</code> (debit)</td></tr><tr><td>Note</td><td>admin-supplied or auto-generated</td></tr><tr><td>Status</td><td>completed / pending / failed</td></tr></tbody></table><p>Filter by:</p><ul><li>Type (credits / debits / all)</li><li>Date range</li><li>Note text search</li></ul><p>Pagination: configurable per <code>wkafw_wallet_ledger_per_page</code> (default 25).</p><h2 id="transaction-types" tabindex="-1"><a class="header-anchor" href="#transaction-types"><span>Transaction types</span></a></h2><table><thead><tr><th>Type</th><th>Sign</th><th>Source</th></tr></thead><tbody><tr><td><strong>Top-up</strong></td><td>+ (credit)</td><td>Customer pays via gateway</td></tr><tr><td><strong>Transfer in</strong></td><td>+ (credit)</td><td>Another customer sent money</td></tr><tr><td><strong>Auction win debit</strong></td><td>− (debit)</td><td>Won auction auto-charged</td></tr><tr><td><strong>Fee charge</strong></td><td>− (debit)</td><td>Platform fee debited</td></tr><tr><td><strong>Manual credit</strong></td><td>+ (credit)</td><td>Admin top-up / refund</td></tr><tr><td><strong>Manual debit</strong></td><td>− (debit)</td><td>Admin debit (rare)</td></tr><tr><td><strong>Withdrawal</strong></td><td>− (debit)</td><td>Approved payout</td></tr><tr><td><strong>Withdrawal reversal</strong></td><td>+ (credit)</td><td>Rejected withdrawal returned</td></tr><tr><td><strong>Transfer out</strong></td><td>− (debit)</td><td>Sent to another customer</td></tr></tbody></table><h2 id="wallet-transfer" tabindex="-1"><a class="header-anchor" href="#wallet-transfer"><span>Wallet Transfer</span></a></h2><p>If enabled (submodule setting), customers can send money peer-to-peer.</p><h3 id="flow" tabindex="-1"><a class="header-anchor" href="#flow"><span>Flow</span></a></h3><ol><li>Click <strong>Wallet Transfer</strong> in the page header</li><li>Enter recipient&#39;s email — autocomplete suggests known users</li><li>Enter amount</li><li>Enter optional note</li><li>Click <strong>Send</strong></li><li><strong>OTP verification</strong> — system sends a one-time code (email or SMS) to the sender</li><li>Enter OTP → confirm</li><li>Funds move atomically — sender debited, recipient credited</li></ol><table><thead><tr><th>Setting</th><th>Default</th></tr></thead><tbody><tr><td>OTP required</td><td>yes</td></tr><tr><td>OTP method</td><td>email (configurable to SMS via <a href="/twilio.html" target="_blank" rel="noopener noreferrer">Twilio</a>)</td></tr><tr><td>OTP validity</td><td>5 minutes</td></tr><tr><td>Max transfer per day</td><td>(configurable; default unlimited)</td></tr><tr><td>Min transfer</td><td>1</td></tr><tr><td>Transfer fee</td><td>0 (configurable)</td></tr></tbody></table><h3 id="security" tabindex="-1"><a class="header-anchor" href="#security"><span>Security</span></a></h3><p>Every transfer is logged to the <a href="/admin-audit-log.html" target="_blank" rel="noopener noreferrer">Audit Log</a> with sender + recipient + amount + IP + timestamp. Reversals require admin approval.</p><h2 id="paying-with-wallet-at-checkout" tabindex="-1"><a class="header-anchor" href="#paying-with-wallet-at-checkout"><span>Paying with wallet at checkout</span></a></h2><p>When the user has wallet balance ≥ cart total, <strong>Wallet</strong> appears as a payment method on checkout.</p><table><thead><tr><th>Cart total</th><th>Wallet balance</th><th>Behavior</th></tr></thead><tbody><tr><td>$100</td><td>$200</td><td>Pay full $100 from wallet (sole payment method)</td></tr><tr><td>$100</td><td>$50</td><td>Two options: top up first, OR partial-pay $50 wallet + $50 gateway</td></tr></tbody></table><h3 id="partial-pay" tabindex="-1"><a class="header-anchor" href="#partial-pay"><span>Partial pay</span></a></h3><p>If <code>wkwc_wallet_partial_pay = yes</code>:</p><ol><li>Customer ticks <strong>Use wallet balance</strong> at checkout</li><li>Wallet drains to zero (or up to cart total)</li><li>Remainder paid via gateway</li><li>Order combines both payment sources</li></ol><div class="hint-container warning"><p class="hint-container-title">Partial pay = two transactions</p><p>Partial-paid orders show two ledger entries: one wallet debit + one gateway charge. Refunds work in reverse — refunded amount goes back to whichever source was charged.</p></div><h2 id="auto-charge" tabindex="-1"><a class="header-anchor" href="#auto-charge"><span>Auto-charge</span></a></h2><p>If <a href="/wallet-auto-charge.html" target="_blank" rel="noopener noreferrer">auto-charge winner</a> is enabled and the customer has balance, won auctions auto-debit on close — no checkout flow needed.</p><h2 id="withdrawal" tabindex="-1"><a class="header-anchor" href="#withdrawal"><span>Withdrawal</span></a></h2><p>To withdraw wallet balance to bank / PayPal:</p><p><strong>My Account → Withdrawal</strong> → <a href="/customer-withdrawal.html" target="_blank" rel="noopener noreferrer">full reference</a>.</p><h2 id="notifications" tabindex="-1"><a class="header-anchor" href="#notifications"><span>Notifications</span></a></h2><table><thead><tr><th>Trigger</th><th>Email</th></tr></thead><tbody><tr><td>Top-up successful</td><td>&quot;Wallet credited&quot;</td></tr><tr><td>Transfer received</td><td>&quot;Money received from {sender}&quot;</td></tr><tr><td>Transfer sent</td><td>&quot;You sent money to {recipient}&quot;</td></tr><tr><td>Wallet debited (auction win)</td><td>&quot;Auction win charged to wallet&quot;</td></tr><tr><td>Withdrawal requested</td><td>&quot;Withdrawal under review&quot;</td></tr><tr><td>Withdrawal approved</td><td>&quot;Withdrawal sent&quot;</td></tr><tr><td>Withdrawal rejected</td><td>&quot;Withdrawal could not be processed&quot;</td></tr></tbody></table><p>Templates editable in <strong>WooCommerce → Settings → Emails</strong>.</p><h2 id="privacy" tabindex="-1"><a class="header-anchor" href="#privacy"><span>Privacy</span></a></h2><p>The page shows only the logged-in user&#39;s own ledger. Even admins viewing the <a href="/admin-wallet.html" target="_blank" rel="noopener noreferrer">admin wallet page</a> see the same data, but in read-write mode.</p><p>GDPR exporter includes the full ledger.</p><h2 id="common-questions" tabindex="-1"><a class="header-anchor" href="#common-questions"><span>Common questions</span></a></h2><p><strong>&quot;Why doesn&#39;t Wallet appear at checkout?&quot;</strong></p><p>Either: (a) balance &lt; cart total and partial-pay is disabled, or (b) the wallet gateway isn&#39;t enabled in <strong>WooCommerce → Settings → Payments</strong>. The plugin auto-injects it but a custom checkout layout may suppress it.</p><p><strong>&quot;Can I see my full top-up history including failed attempts?&quot;</strong></p><p>Yes — switch the filter to <strong>All</strong> instead of just completed. Failed top-ups show with status = <code>failed</code>.</p><p><strong>&quot;My balance shows wrong&quot;</strong></p><p>Run <a href="/admin-tools.html#database" target="_blank" rel="noopener noreferrer">Tools → Database → Recompute totals</a> — admin-only, but it re-aggregates the ledger and refreshes the cached balance.</p>',50)])])}]]),o=JSON.parse('{"path":"/customer-wallet.html","title":"My Wallet","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"What the page shows","slug":"what-the-page-shows","link":"#what-the-page-shows","children":[]},{"level":2,"title":"Adding funds (top-up)","slug":"adding-funds-top-up","link":"#adding-funds-top-up","children":[]},{"level":2,"title":"Transactions ledger","slug":"transactions-ledger","link":"#transactions-ledger","children":[]},{"level":2,"title":"Transaction types","slug":"transaction-types","link":"#transaction-types","children":[]},{"level":2,"title":"Wallet Transfer","slug":"wallet-transfer","link":"#wallet-transfer","children":[{"level":3,"title":"Flow","slug":"flow","link":"#flow","children":[]},{"level":3,"title":"Security","slug":"security","link":"#security","children":[]}]},{"level":2,"title":"Paying with wallet at checkout","slug":"paying-with-wallet-at-checkout","link":"#paying-with-wallet-at-checkout","children":[{"level":3,"title":"Partial pay","slug":"partial-pay","link":"#partial-pay","children":[]}]},{"level":2,"title":"Auto-charge","slug":"auto-charge","link":"#auto-charge","children":[]},{"level":2,"title":"Withdrawal","slug":"withdrawal","link":"#withdrawal","children":[]},{"level":2,"title":"Notifications","slug":"notifications","link":"#notifications","children":[]},{"level":2,"title":"Privacy","slug":"privacy","link":"#privacy","children":[]},{"level":2,"title":"Common questions","slug":"common-questions","link":"#common-questions","children":[]}],"git":{},"filePathRelative":"customer-wallet.md"}')}}]);